"use client";

import { useState } from "react";
import { motion } from "framer-motion";
import { X, Minus, Plus, Trash2 } from "lucide-react";
import Image from "next/image";
import { Button } from "@/components/ui/button";

export default function CartSidebar() {
    const [open, setOpen] = useState(true);
    const [items, setItems] = useState([
        {
            id: 1,
            name: "Be Nice Shower Cream, Perfect Elastic Formula, 450 ml.",
            price: 109,
            qty: 1,
            stock: 200,
            image: "/images/benice.jpg",
        },
        {
            id: 2,
            name: "Protex Lavender Ice Freeze Soap Bar 60 g.",
            price: 57,
            qty: 3,
            stock: 359,
            image: "/images/protex.jpg",
        },
        {
            id: 3,
            name: "KFC BamBam BOX Menu TheBox special",
            price: 159,
            qty: 1,
            stock: 20,
            image: "/images/kfc.jpg",
        },
    ]);

    const handleQty = (id: number, type: "inc" | "dec") => {
        setItems((prev) =>
            prev.map((item) =>
                item.id === id
                    ? {
                        ...item,
                        qty: type === "inc" ? item.qty + 1 : Math.max(1, item.qty - 1),
                    }
                    : item
            )
        );
    };

    const handleRemove = (id: number) => {
        setItems((prev) => prev.filter((item) => item.id !== id));
    };

    const total = items.reduce((acc, item) => acc + item.price * item.qty, 0);

    return (
        <>
            {/* Overlay */}
            {open && (
                <motion.div
                    initial={{ opacity: 0 }}
                    animate={{ opacity: 0.4 }}
                    exit={{ opacity: 0 }}
                    className="fixed inset-0 bg-black z-40"
                    onClick={() => setOpen(false)}
                />
            )}

            {/* Sidebar */}
            <motion.div
                initial={{ x: "100%" }}
                animate={{ x: open ? 0 : "100%" }}
                transition={{ type: "spring", damping: 20, stiffness: 120 }}
                className="fixed top-0 right-0 h-full w-[420px] bg-white shadow-lg z-50 flex flex-col"
            >
                {/* Header */}
                <div className="flex items-center justify-between p-4 border-b">
                    <h2 className="text-lg font-semibold">Shop cart</h2>
                    <button onClick={() => setOpen(false)}>
                        <X size={22} />
                    </button>
                </div>

                {/* Tabs */}
                <div className="flex items-center gap-2 px-4 py-2 border-b text-sm">
          <span className="text-green-600 font-medium cursor-pointer">
            ShopCart
          </span>
                    <span>/</span>
                    <span className="text-gray-500 cursor-pointer">Order</span>
                </div>

                {/* Items */}
                <div className="flex-1 overflow-y-auto divide-y">
                    {items.map((item) => (
                        <div key={item.id} className="flex gap-3 p-4">
                            <div className="relative w-16 h-16 flex-shrink-0">
                                <Image
                                    src={item.image}
                                    alt={item.name}
                                    fill
                                    className="rounded-md object-cover"
                                />
                            </div>
                            <div className="flex-1">
                                <p className="text-sm font-medium">{item.name}</p>
                                <p className="text-xs text-gray-500">
                                    In stock : {item.stock}
                                </p>
                                <button
                                    className="text-xs text-red-500 flex items-center gap-1 mt-1"
                                    onClick={() => handleRemove(item.id)}
                                >
                                    <Trash2 size={12} /> Remove
                                </button>
                            </div>
                            <div className="flex flex-col items-end justify-between">
                                {/* Qty control */}
                                <div className="flex items-center border rounded">
                                    <button
                                        className="px-2 py-1 hover:bg-gray-100"
                                        onClick={() => handleQty(item.id, "dec")}
                                    >
                                        <Minus size={14} />
                                    </button>
                                    <span className="px-3">{item.qty}</span>
                                    <button
                                        className="px-2 py-1 hover:bg-gray-100"
                                        onClick={() => handleQty(item.id, "inc")}
                                    >
                                        <Plus size={14} />
                                    </button>
                                </div>
                                {/* Price */}
                                <p className="text-sm font-semibold">
                                    ${item.price.toFixed(2)}
                                </p>
                            </div>
                        </div>
                    ))}
                </div>

                {/* Footer */}
                <div className="border-t p-4">
                    <Button className="w-full bg-green-600 hover:bg-green-700 text-white rounded-md py-6">
                        Payment ${total.toFixed(2)}
                    </Button>
                </div>
            </motion.div>
        </>
    );
}
